class Solution:
    def minimizeStringValue(self, s: str) -> str:
        res = []
        last = {}
        for c in s:
            if c == '?':
                for i in range(26):
                    if chr(i + 97) not in last:
                        res.append(chr(i + 97))
                        last[chr(i + 97)] = 1
                        break
            else:
                res.append(c)
                last[c] = last.get(c, 0) + 1
        return ''.join(res)
